Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportMonitoraEnvioWhatsapp-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&EmpCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Empresa") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &EmpCod EndIf
If not (&FilaWhatsTip.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Tipo") If Not &FilaWhatsTip.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &FilaWhatsTip.EnumerationDescription() Endif EndIf
If not (&FilaWhatsSts.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Status") If Not &FilaWhatsSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &FilaWhatsSts.EnumerationDescription() Endif EndIf
If not (&FilaWhatsMsgCreCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Duplicata") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilaWhatsMsgCreCod EndIf
If not (&FilaWhatsDestPesCod.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Cliente") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &FilaWhatsDestPesCod EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'FILAWHATSDTAEMS' &FilaWhatsDtaEms1.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaEms_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaEms1.IsEmpty() OR not &FilaWhatsDtaEms_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaEms1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaEms_To1 EndIf Case &DynamicFiltersSelector1 = !'FILAWHATSDTAENV' &FilaWhatsDtaEnv1.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaEnv_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaEnv1.IsEmpty() OR not &FilaWhatsDtaEnv_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Enviado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaEnv1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaEnv_To1 EndIf Case &DynamicFiltersSelector1 = !'FILAWHATSDTALIM' &FilaWhatsDtaLim1.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaLim_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaLim1.IsEmpty() OR not &FilaWhatsDtaLim_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Limite" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaLim1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaLim_To1 EndIf Case &DynamicFiltersSelector1 = !'FILAWHATSDTAULTTEN' &FilaWhatsDtaUltTen1.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaUltTen_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaUltTen1.IsEmpty() OR not &FilaWhatsDtaUltTen_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Últ. Tent." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaUltTen1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaUltTen_To1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'FILAWHATSDTAEMS' &FilaWhatsDtaEms2.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaEms_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaEms2.IsEmpty() OR not &FilaWhatsDtaEms_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaEms2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaEms_To2 EndIf Case &DynamicFiltersSelector2 = !'FILAWHATSDTAENV' &FilaWhatsDtaEnv2.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaEnv_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaEnv2.IsEmpty() OR not &FilaWhatsDtaEnv_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Enviado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaEnv2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaEnv_To2 EndIf Case &DynamicFiltersSelector2 = !'FILAWHATSDTALIM' &FilaWhatsDtaLim2.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaLim_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaLim2.IsEmpty() OR not &FilaWhatsDtaLim_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Limite" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaLim2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaLim_To2 EndIf Case &DynamicFiltersSelector2 = !'FILAWHATSDTAULTTEN' &FilaWhatsDtaUltTen2.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaUltTen_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaUltTen2.IsEmpty() OR not &FilaWhatsDtaUltTen_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Últ. Tent." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaUltTen2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaUltTen_To2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'FILAWHATSDTAEMS' &FilaWhatsDtaEms3.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaEms_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaEms3.IsEmpty() OR not &FilaWhatsDtaEms_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaEms3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaEms_To3 EndIf Case &DynamicFiltersSelector3 = !'FILAWHATSDTAENV' &FilaWhatsDtaEnv3.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaEnv_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaEnv3.IsEmpty() OR not &FilaWhatsDtaEnv_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Enviado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaEnv3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaEnv_To3 EndIf Case &DynamicFiltersSelector3 = !'FILAWHATSDTALIM' &FilaWhatsDtaLim3.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaLim_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaLim3.IsEmpty() OR not &FilaWhatsDtaLim_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Limite" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaLim3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaLim_To3 EndIf Case &DynamicFiltersSelector3 = !'FILAWHATSDTAULTTEN' &FilaWhatsDtaUltTen3.FromString(&GridStateDynamicFilter.Value) &FilaWhatsDtaUltTen_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &FilaWhatsDtaUltTen3.IsEmpty() OR not &FilaWhatsDtaUltTen_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Últ. Tent." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &FilaWhatsDtaUltTen3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "WWP_MiddleText" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &FilaWhatsDtaUltTen_To3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
