Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Status" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Qtd. Tent." &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Ult. Tent." &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Emissão" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Enviado" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Limite" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Log" &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Tipo"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod when &OrderedBy = 1 order FilaWhatsSts when &OrderedBy = 2 AND &OrderedDsc = False order (FilaWhatsSts) when &OrderedBy = 2 AND &OrderedDsc = True order FilaWhatsQtdTen when &OrderedBy = 3 AND &OrderedDsc = False order (FilaWhatsQtdTen) when &OrderedBy = 3 AND &OrderedDsc = True order FilaWhatsDtaUltTen when &OrderedBy = 4 AND &OrderedDsc = False order (FilaWhatsDtaUltTen) when &OrderedBy = 4 AND &OrderedDsc = True order FilaWhatsDtaEms when &OrderedBy = 5 AND &OrderedDsc = False order (FilaWhatsDtaEms) when &OrderedBy = 5 AND &OrderedDsc = True order FilaWhatsDtaEnv when &OrderedBy = 6 AND &OrderedDsc = False order (FilaWhatsDtaEnv) when &OrderedBy = 6 AND &OrderedDsc = True order FilaWhatsDtaLim when &OrderedBy = 7 AND &OrderedDsc = False order (FilaWhatsDtaLim) when &OrderedBy = 7 AND &OrderedDsc = True order FilaWhatsLog when &OrderedBy = 8 AND &OrderedDsc = False order (FilaWhatsLog) when &OrderedBy = 8 AND &OrderedDsc = True order FilaWhatsTip when &OrderedBy = 9 AND &OrderedDsc = False order (FilaWhatsTip) when &OrderedBy = 9 AND &OrderedDsc = True
using DSMonitoraEnvioWhatsapp(&EmpCod, &FilaWhatsTip, &FilaWhatsSts, &FilaWhatsMsgCreCod, &FilaWhatsDestPesCod, &DynamicFiltersSelector1 , &FilaWhatsDtaEms1, &FilaWhatsDtaEms_To1, &FilaWhatsDtaEnv1, &FilaWhatsDtaEnv_To1, &FilaWhatsDtaLim1, &FilaWhatsDtaLim_To1 , &FilaWhatsDtaUltTen1, &FilaWhatsDtaUltTen_To1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &FilaWhatsDtaEms2, &FilaWhatsDtaEms_To2 , &FilaWhatsDtaEnv2, &FilaWhatsDtaEnv_To2, &FilaWhatsDtaLim2, &FilaWhatsDtaLim_To2, &FilaWhatsDtaUltTen2, &FilaWhatsDtaUltTen_To2 , &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &FilaWhatsDtaEms3, &FilaWhatsDtaEms_To3, &FilaWhatsDtaEnv3, &FilaWhatsDtaEnv_To3 , &FilaWhatsDtaLim3, &FilaWhatsDtaLim_To3, &FilaWhatsDtaUltTen3, &FilaWhatsDtaUltTen_To3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = FilaWhatsSts.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = FilaWhatsQtdTen &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Date = FilaWhatsDtaUltTen &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = FilaWhatsDtaEms &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Date = FilaWhatsDtaEnv &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Date = FilaWhatsDtaLim &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = WWP_Export_SecureText(FilaWhatsLog) &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = FilaWhatsTip.EnumerationDescription()
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"MonitoraEnvioWhatsappGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"MonitoraEnvioWhatsappGridState")) Else &GridState.FromXml(&Session.Get(!"MonitoraEnvioWhatsappGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"EMPCOD" &EmpCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILAWHATSTIP" &FilaWhatsTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILAWHATSSTS" &FilaWhatsSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILAWHATSMSGCRECOD" &FilaWhatsMsgCreCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILAWHATSDESTPESCOD" &FilaWhatsDestPesCod.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
